## 2. Build script (`setup.py`)

```python
# setup.py
# --------------------------------------------------------------
# Build the pybind11‑based extension.  Works with any recent
# Python (3.8+) and a C++17 compiler.
# --------------------------------------------------------------

import os
import sys
import pathlib
from setuptools import setup, Extension
from setuptools.command.build_ext import build_ext

# --------------------------------------------------------------
# Helper to locate the pybind11 include directory.
# --------------------------------------------------------------
class get_pybind_include(object):
    """Helper class to determine the pybind11 include path."""
    def __str__(self):
        import pybind11
        return pybind11.get_include()


ext_modules = [
    Extension(
        "blocksci",                         # name of the generated .so
        ["blocksci_binding.cpp"],           # our single source file
        include_dirs=[
            # Path to pybind11 headers
            get_pybind_include(),
        ],
        language="c++",
        extra_compile_args=["-O3", "-std=c++17"],
    ),
]

# --------------------------------------------------------------
# Custom build_ext to add compiler‑specific flags.
# --------------------------------------------------------------
class BuildExt(build_ext):
    c_opts = {
        "msvc": ["/EHsc", "/O2"],
        "unix": ["-O3", "-march=native"],
    }

    def build_extensions(self):
        ct = self.compiler.compiler_type
        opts = self.c_opts.get(ct, [])
        for ext in self.extensions:
            ext.extra_compile_args = opts
        super().build_extensions()


setup(
    name="blocksci",
    version="0.1.0",
    author="Your Name",
    description="Python bindings for the BlockSci blockchain analytics engine",
    long_description="See the source for a minimal example that mimics the real BlockSci API.",
    ext_modules=ext_modules,
    cmdclass={"build_ext": BuildExt},
    zip_safe=False,
)
```

### How to compile & install

```bash
# 1️⃣  Create a fresh virtualenv (optional but recommended)
python -m venv venv
source venv/bin/activate

# 2️⃣  Install pybind11 (the only external requirement)
pip install pybind11

# 3️⃣  Build & install the extension
pip install -e .
#   -e . tells pip to install the package in “editable” mode, i.e.
#   you can re‑run `pip install -e .` after editing the C++ source.
```

After the build succeeds you will have a `blocksci` Python package with a compiled `_blocksci.cpython-…-x86_64-linux-gnu.so` file.

